     * This is equivalent to finding the index where X should be inserted to maintain order (lower_bound).
     * Since all elements are distinct, this count is the number of elements < X.
     * @param {number[]} sortedArr 
     * @param {number} X 
     * @returns {number} The count of elements < X.
     */
    const count_lt = (sortedArr, X) => {
        let low = 0;
        let high = sortedArr.length;
        let count = 0;

        // Binary search to find the first element >= X
        while (low < high) {
            let mid = Math.floor((low + high) / 2);
            if (sortedArr[mid] < X) {
                // All elements up to mid are less than X. Try higher.
                count = mid + 1;
                low = mid + 1;
            } else {
